            }
          ],
          "spans": [
            {
              "offset": 5082,
              "length": 210
            }
          ]
        },
        {
          "content": "bilgilerinize rica ederiz.",
          "polygon": [
            {
              "x": 0.4911,
              "y": 10.5244
            },
            {
              "x": 1.288,
              "y": 10.5249
            },
